const msg = $input.first().json;
const type = msg.type || 'unknown';

const typeMap = {
  text:     () => msg.text?.body || '',
  image:    () => '[Le client a envoyé une image]',
  audio:    () => '[Le client a envoyé un message vocal]',
  video:    () => '[Le client a envoyé une vidéo]',
  document: () => '[Le client a envoyé un document : ' + (msg.document?.filename || '') + ']',
  sticker:  () => '[Le client a envoyé un sticker]',
  location: () => '[Le client a partagé sa localisation]',
  reaction: () => null,
};

const texte = (typeMap[type] || (() => `[${type}]`))();
if (!texte) return [];

const from = msg.from;
const name = msg.profileName || ('+' + from);

return [{ json: { from, name, texte, type } }];

const data   = $input.first().json;
const msg    = $('Extraire message').first().json;
const orders = data.orders || [];

const statusLabel = { en_attente: 'En attente', disponible: 'Disponible (prêt à récupérer)', recupere: 'Récupéré' };
const modeLabel   = { avion: 'EXPRESS ✈️', bateau: 'ECO 🚢' };

let contexteCommandes = '';

if (!data.found || orders.length === 0) {
  contexteCommandes = 'Ce client n\'a aucune commande enregistrée dans notre système.';
} else {
  const lignes = orders.map((o, i) => {
    const produits = (o.products || []).map(p => `  • ${p.quantity}x ${p.name} (${p.condition})`).join('\n');
    const date = o.created_at ? new Date(o.created_at).toLocaleDateString('fr-FR') : '?';
    return `Commande ${i+1} : ${o.order_number}
  Date : ${date}
  Statut : ${statusLabel[o.status] || o.status}
  Mode : ${modeLabel[o.delivery_type] || o.delivery_type}
  Total : ${o.total_amount?.toLocaleString('fr-FR')} FCFA
  Acompte payé : ${o.deposit?.toLocaleString('fr-FR')} FCFA
  Reste à payer : ${o.remaining_balance?.toLocaleString('fr-FR')} FCFA
  Produits :
${produits}`;
  });
  contexteCommandes = lignes.join('\n\n');
}

return [{ json: {
  from: msg.from,
  name: msg.name,
  texte: msg.texte,
  contexteCommandes
} }];

const data = $input.first().json;
const reponse = data.choices?.[0]?.message?.content?.trim()
  || 'Bonjour ! Notre équipe revient vers vous très vite. Pour une urgence : *+228 90 22 64 91* — *TOGOLESE* 🛒';
const from = $('Extraire message').first().json.from;
return [{ json: { from, reponse } }];
